    /// Returns the named Codicon as a template image, tinted by the button's
    /// `contentTintColor` to match the rest of the activity bar.
    static func codicon(_ name: String, pointSize: CGFloat) -> NSImage? {
        guard let raw = svgs[name] else { return nil }
        // `currentColor` doesn't resolve in NSImage's SVG rep, so force an
        // opaque fill; the resulting solid mask is what template tinting needs.
        let svg = raw.replacingOccurrences(of: "currentColor", with: "#000000")
        guard let data = svg.data(using: .utf8),
              let image = NSImage(data: data) else { return nil }
        image.isTemplate = true
        image.size = NSSize(width: pointSize, height: pointSize)
        return image
    }
}
